    45→            sb.append(character.getValue());
    46→        }
    47→
    48→        // Concatenate single quotes; this will automatically call sb.toString()
    49→        return "'" + sb + "'";
    50→    }
    51→
    52→    /**
    53→     * Compares this to the input object by value; a wrapper around the implementation
