    55→     *
    56→     * @param obj the object to compare against
    57→     * @return true if this is equivalent by value to obj; false otherwise
    58→     */
    59→    @Override
    60→    public boolean equals(Object obj) {
    61→        if (!(obj instanceof PyStringObj)) {
    62→            return false;
    63→        }
    64→        return super.equals(obj);
    65→    }
    66→}

