    11→public class PyDictObj<KeyType extends APyObj, ValType extends APyObj> extends APyObj {
    12→
    13→    /**
    14→     * The contents of this PyDictObj.
    15→     */
    16→    private final Map<KeyType, ValType> value;
    17→
    18→    /**
    19→     * Constructor for a PyDictObj; initializes its value to the input.
    20→     *
    21→     * @param value the value of this PyDictObj
    22→     */
    23→    public PyDictObj(Map<KeyType, ValType> value) {
    24→        this.value = value;
    25→    }
    26→
    27→    /**
    28→     * Returns the underlying (Java Map) representation of this PyDictObj.
    29→     *
    30→     * @return the underlying (Java Map) representation of this PyDictObj
    31→     */
    32→    @Override
    33→    public Map<KeyType, ValType> getValue() {
    34→        return this.value;
    35→    }
    36→
    37→    /**
    38→     * Builds and returns a string representation of this object that mirrors the Python
    39→     * string representation (i.e., {key1: val1, key2: val2, ...}).
    40→     *
    41→     * @return a string representation of this object
    42→     */
    43→    @Override
    44→    public String toString() {
    45→        StringBuilder repr = new StringBuilder("{");
    46→
    47→        // Add all of the (key, value) pairs
