    49→            String key = entry.getKey().toString();
    50→            String val = entry.getValue().toString();
    51→            repr.append(key).append(": ").append(val).append(", ");
    52→        }
    53→
    54→        // Remove last ", "
    55→        if (this.value.size() > 0) {
    56→            repr = new StringBuilder(repr.substring(0, repr.length() - 2));
    57→        }
    58→
    59→        repr.append("}");
    60→        return repr.toString();
    61→    }
    62→}

