package main.rice.node;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * Abstract base class for all Python node types. Each node represents
 * a domain of possible Python values and can generate exhaustive or
 * random samples from that domain.
 *
 * @param <T> the type of Python object this node generates
 */
public abstract class APyNode<T extends APyObj> {

    /** The exhaustive domain specification (e.g., list of values or lengths). */
    protected List<Integer> exDomain;

    /** The random domain specification (e.g., list of values or lengths). */
    protected List<Integer> ranDomain;

    /**
     * Sets the exhaustive domain.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = new ArrayList<>(exDomain);
    }

    /**
     * Returns the exhaustive domain.
     *
     * @return the exhaustive domain
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the random domain.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = new ArrayList<>(ranDomain);
    }

    /**
     * Returns the random domain.
     *
     * @return the random domain
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Generates all exhaustive values in this node's domain.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<T> genExVals();

    /**
     * Generates a single random value from this node's random domain.
     *
     * @return a random value
     */
    public abstract T genRandVal();
}

package main.rice.node;

import main.rice.obj.APyObj;

/**
 * Abstract base class for iterable Python node types (list, set, tuple, etc.).
 * Has a left child node that generates the elements of the iterable.
 *
 * @param <T> the type of Python object this node generates (e.g., PyListObj)
 */
public abstract class AIterablePyNode<T extends APyObj> extends APyNode<T> {

    /** The child node used to generate individual elements. */
    protected APyNode<?> leftChild;

    /**
     * Returns the left child node.
     *
     * @return the left child node
     */
    public APyNode<?> getLeftChild() {
        return leftChild;
    }
}

package main.rice.node;

import main.rice.obj.PyIntObj;
import java.util.*;

/**
 * A node that generates Python int values.
 * The exDomain and ranDomain contain the actual integer values (not lengths).
 */
public class PyIntNode extends APyNode<PyIntObj> {

    private static final Random RAND = new Random();

    /**
     * Generates all exhaustive int values from the exDomain.
     *
     * @return a set of PyIntObj values, one per value in exDomain
     */
    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> result = new LinkedHashSet<>();
        for (Integer val : exDomain) {
            result.add(new PyIntObj(val));
        }
        return result;
    }

    /**
     * Generates a single random PyIntObj chosen uniformly from ranDomain.
     *
     * @return a random PyIntObj
     */
    @Override
    public PyIntObj genRandVal() {
        return new PyIntObj(ranDomain.get(RAND.nextInt(ranDomain.size())));
    }
}

package main.rice.node;

import main.rice.obj.*;
import java.util.*;

/**
 * A node that generates Python list values.
 * The exDomain and ranDomain contain possible list lengths.
 * Elements are generated by the left child node.
 *
 * @param <InnerType> the type of each element in the list
 */
public class PyListNode<InnerType extends APyObj>
        extends AIterablePyNode<PyListObj<InnerType>> {

    private static final Random RAND = new Random();

    /**
     * Constructs a PyListNode with the given element-generating child node.
     *
     * @param leftChild the node used to generate list elements
     */
    public PyListNode(APyNode<InnerType> leftChild) {
        this.leftChild = leftChild;
    }

    /**
     * Generates all exhaustive list values. For each length in exDomain,
     * produces all sequences (with repetition) of that length from the
     * child's exhaustive values.
     *
     * @return a set of all exhaustive PyListObj values
     */
    @Override
    @SuppressWarnings("unchecked")
    public Set<PyListObj<InnerType>> genExVals() {
        APyNode<InnerType> child = (APyNode<InnerType>) leftChild;
        List<InnerType> childVals = new ArrayList<>(child.genExVals());
        Set<PyListObj<InnerType>> result = new HashSet<>();
        for (int len : exDomain) {
            for (List<InnerType> seq : genSequences(childVals, len)) {
                result.add(new PyListObj<>(seq));
            }
        }
        return result;
    }

    /**
     * Generates a single random list by choosing a length uniformly from
     * ranDomain and filling it with random elements from the child node.
     *
     * @return a random PyListObj
     */
    @Override
    @SuppressWarnings("unchecked")
    public PyListObj<InnerType> genRandVal() {
        APyNode<InnerType> child = (APyNode<InnerType>) leftChild;
        int len = ranDomain.get(RAND.nextInt(ranDomain.size()));
        List<InnerType> elements = new ArrayList<>();
        for (int i = 0; i < len; i++) {
            elements.add(child.genRandVal());
        }
        return new PyListObj<>(elements);
    }

    /**
     * Recursively generates all sequences of the given length from vals,
     * allowing repetition (order matters).
     *
     * @param vals the pool of values to draw from
     * @param len  the target sequence length
     * @return all length-len sequences with repetition
     */
    private List<List<InnerType>> genSequences(List<InnerType> vals, int len) {
        List<List<InnerType>> result = new ArrayList<>();
        if (len == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        for (List<InnerType> sub : genSequences(vals, len - 1)) {
            for (InnerType val : vals) {
                List<InnerType> newSeq = new ArrayList<>(sub);
                newSeq.add(val);
                result.add(newSeq);
            }
        }
        return result;
    }
}

package main.rice.node;

import main.rice.obj.*;
import java.util.*;

/**
 * A node that generates Python set values.
 * The exDomain and ranDomain contain possible set sizes.
 * Elements are generated by the left child node.
 * Sets do not allow duplicate elements.
 *
 * @param <InnerType> the type of each element in the set
 */
public class PySetNode<InnerType extends APyObj>
        extends AIterablePyNode<PySetObj<InnerType>> {

    private static final Random RAND = new Random();

    /**
     * Constructs a PySetNode with the given element-generating child node.
     *
     * @param leftChild the node used to generate set elements
     */
    public PySetNode(APyNode<InnerType> leftChild) {
        this.leftChild = leftChild;
    }

    /**
     * Generates all exhaustive set values. For each size in exDomain,
     * produces all subsets (combinations without repetition) of that size
     * from the child's exhaustive values.
     *
     * @return a set of all exhaustive PySetObj values
     */
    @Override
    @SuppressWarnings("unchecked")
    public Set<PySetObj<InnerType>> genExVals() {
        APyNode<InnerType> child = (APyNode<InnerType>) leftChild;
        List<InnerType> childVals = new ArrayList<>(child.genExVals());
        Set<PySetObj<InnerType>> result = new HashSet<>();
        for (int size : exDomain) {
            for (Set<InnerType> subset : genSubsets(childVals, size)) {
                result.add(new PySetObj<>(subset));
            }
        }
        return result;
    }

    /**
     * Generates a single random set by choosing a size uniformly from
     * ranDomain and filling it with distinct random elements from the child.
     *
     * @return a random PySetObj
     */
    @Override
    @SuppressWarnings("unchecked")
    public PySetObj<InnerType> genRandVal() {
        APyNode<InnerType> child = (APyNode<InnerType>) leftChild;
        int size = ranDomain.get(RAND.nextInt(ranDomain.size()));
        Set<InnerType> elements = new LinkedHashSet<>();
        while (elements.size() < size) {
            elements.add(child.genRandVal());
        }
        return new PySetObj<>(elements);
    }

    /**
     * Recursively generates all subsets of the given size from vals
     * (combinations without repetition, order does not matter).
     *
     * @param vals the pool of values to draw from
     * @param size the target subset size
     * @return all size-element subsets
     */
    private List<Set<InnerType>> genSubsets(List<InnerType> vals, int size) {
        List<Set<InnerType>> result = new ArrayList<>();
        if (size == 0) {
            result.add(new LinkedHashSet<>());
            return result;
        }
        if (size > vals.size()) {
            return result;
        }
        for (int i = 0; i <= vals.size() - size; i++) {
            InnerType elem = vals.get(i);
            List<InnerType> remaining = vals.subList(i + 1, vals.size());
            for (Set<InnerType> sub : genSubsets(remaining, size - 1)) {
                Set<InnerType> newSet = new LinkedHashSet<>();
                newSet.add(elem);
                newSet.addAll(sub);
                result.add(newSet);
            }
        }
        return result;
    }
}

